head.script:
//전역변수
scwin.login = "";
scwin.clntNo = "";
scwin.clntNm = "";

scwin.curRow = -1;
//-------------------------------------------------------------------------
// TOBE : 초기로드(UDC 있으면 scwin.onUdcCompleted 초기값 세팅)
//-------------------------------------------------------------------------
scwin.onpageload = function () {
    // 회원정보를 json 데이터로 모두 받음
    scwin.login = $c.data.getMemInfo();
    scwin.clntNo = scwin.login.clntNo;
    scwin.clntNm = scwin.login.clntNm;

    var codeOptions = [
        { grpCd: "TL116", compID: "lc_oilkndCd, gr_oilInOut:oilkndCd" }, // 유종
        { grpCd: "TL114", compID: "lc_stsCd, gr_oilInOut:stsCd" } // 판매단가기준
    ];
    $c.data.setCommonCode(codeOptions);
};

scwin.ondataload = async function () {
    lc_oilkndCd.setSelectedIndex(1); //tobe추가 : asis와동일하게 처음에 경유로 표시
    await scwin.f_retrieveOilPrice(); // 유류예측 조회

    //로그인 정보에 거래처있을때 자동셋팅후 입력불가
    if (!$c.gus.cfIsNull(scwin.clntNo)) {
        ed_clntNo.setValue(scwin.clntNo);
        ed_clntNm.setValue(scwin.clntNm);
        gr_oilInOut.setColumnVisible('clntNo', false);
        gr_oilInOut.setColumnVisible('clntNm', false);
        $c.gus.cfDisableObjects([udc_clntNo]);
    }

    scwin.f_getRecentPrice();
};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. onPageLoad 에서 호출 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    lc_dtClsCd.setValue(0);
    lc_reqSelfTransYn.setValue(0); //전체로 표시


    ed_stdDt.setValue($c.date.getServerDateTime("yyyyMM") + "01");
    ed_endDt.setValue($c.date.getServerDateTime("yyyyMMdd"));
};

//-------------------------------------------------------------------------
// function name : f_getRecentPrice
// function desc : 최근의 유류구매공장도단가 조회/Setting
//-------------------------------------------------------------------------
scwin.f_getRecentPrice = function () {
    ed_today.setValue(`(${$c.date.getServerDateTime("yyyy/MM/dd")})`);

    dma_searchRecent.setEmptyValue();

    dma_searchRecent.set('oilBizClsCd', "01");
    dma_searchRecent.set('selpchClsCd', "01");
    dma_searchRecent.set('oilUprrglClsCd', "01");	// 단가구분 : 01 여신, 10 현물	
    dma_searchRecent.set("stdDt", $c.date.addMonth($c.date.getServerDateTime("yyyyMMdd"), -1));	// 전월
    dma_searchRecent.set('oilTskClsCd', "F");
    dma_searchRecent.set("endDt", $c.date.getServerDateTime("yyyyMMdd"));
    dma_searchRecent.set('clntNo', "244974");	// 지에스칼텍스(주)여수공장
    dma_searchRecent.set('payChkCd', "Y");		// 지급구분 : Y인 경우 여신/현물거래 동시 조회 가능

    //최근 공장도단가 조회
    $c.sbm.execute(sbm_retrieveRecent);
};

scwin.sbm_retrieveRecent_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        if (ds_oilUnitPrice.getRowCount() != 0) {
            var uPrice = 0;
            for (var i = 0; i < ds_oilUnitPrice.getRowCount(); i++) {
                if (ds_oilUnitPrice.getCellData(i, "endDt") == "99999999") {
                    uPrice = ds_oilUnitPrice.getCellData(i, "uprLight");
                    uPrice = $c.gus.cfInsertComma(uPrice);
                }
            }
            ed_price.setValue(uPrice);
        }
    }
};

//-------------------------------------------------------------------------
// 예상 등락 조회
//-------------------------------------------------------------------------
scwin.f_retrieveOilPrice = function () {
    scwin.dmaSearch_dataSetting();
    dma_search.set("endDt", $c.date.getServerDateTime("yyyyMMdd"));
    dma_search.set("oilkndCd", "01");

    $c.sbm.execute(sbm_retrieveUpDown);
};

scwin.sbm_retrieveUpDown_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        var plus = 0;
        var minus = 0;
        if (ds_upDown.getRowCount() != 0) {

            plus = $c.num.parseInt(ds_upDown.getCellData(0, "upDown")) + 5;
            minus = $c.num.parseInt(ds_upDown.getCellData(0, "upDown")) - 5;

            if (plus < 0) {
                ed_plus.setValue(plus);
            } else {
                ed_plus.setValue("+" + plus);
            }

            if (minus < 0) {
                ed_minus.setValue(minus);
            } else {
                ed_minus.setValue("+" + minus);
            }
        }
    };
};

//-------------------------------------------------------------------------
// 엑셀 출력
//-------------------------------------------------------------------------
scwin.f_Excel = function () {
    var count = ds_oilInOut.getRowCount();
    if (count <= 0) return;

    var options = {
        fileName: "유류구매요청내역.xlsx",
        sheetName: "유류구매요청내역",
        startRowIndex: 4,
        startColumnIndex: 0,
        type: 1,
    };

    var infoArr = [{
        rowIndex: 0,
        colIndex: 0,
        rowSpan: 1,
        colSpan: 14,
        text: "유류구매요청내역",
        textAlign: "center",
        fontSize: 12,
        drawBorder: false
    }, {
        rowIndex: 2,
        colIndex: 0,
        rowSpan: 1,
        colSpan: 14,
        text: `${lc_dtClsCd.getValue()} [${$c.date.formatDate(ed_stdDt.getValue(), "date")} ~ ${$c.date.formatDate(ed_endDt.getValue(), "date")}]`,
        textAlign: "left",
        fontSize: 10,
        drawBorder: false
    }, {
        rowIndex: 3,
        colIndex: 0,
        rowSpan: 1,
        colSpan: 14,
        text: `거래처 [${ed_clntNm.getValue()}[${ed_clntNo.getValue()}]]`,
        textAlign: "left",
        fontSize: 10,
        drawBorder: false
    }];

    $c.data.downloadGridViewExcel(gr_oilInOut, options, infoArr);
};

//-------------------------------------------------------------------------
// 조회기간 체크
//-------------------------------------------------------------------------
scwin.f_CheckAdptDt = async function () {
    var vAdptStDt = ed_stdDt.getValue();
    var vAdptEndDt = ed_endDt.getValue();

    if (vAdptStDt == "" || vAdptStDt.length < 8) {
        await $c.win.alert("적용시작일자를 정확하게 입력해주십시오.");
        ed_stdDt.focus();
        return false;
    }

    if (vAdptEndDt == "" || vAdptEndDt.length < 8) {
        await $c.win.alert("적용종료일자를 정확하게 입력해주십시오.");
        ed_endDt.focus();
        return false;
    }

    if (!await $c.gus.cfValidate([ed_stdDt, ed_endDt]))
        return false;

    if (!$c.gus.cfIsAfterDate(ed_stdDt.getValue(), ed_endDt.getValue(), false)) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_039); //시작일자가 종료일자 이전이어야 합니다
        ed_stdDt.focus();
        return false;
    }

    return true;
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function (e) {
    var vChkVal = await scwin.f_CheckAdptDt();			//날짜 체크한 결과 값을 리턴
    if (!vChkVal) {					//true or false 결과을 체크하여 잘못들어갔다면, false값 리턴
        return false;
    }

    dma_search.setEmptyValue();
    scwin.dmaSearch_dataSetting();
    dma_search.set("realSelfTransYn", "2");
    //dma_search.UseChangeInfo = "false";
    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        var rowCnt = ds_oilInOut.getRowCount();
        totalRows.setValue(rowCnt);

        if (rowCnt == 0) {
            await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
            return;
        }

        gr_oilInOut.setColumnReadOnly("chk", false);
        gr_oilInOut.setFocusedCell(0, 0);

    }
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function (e) {
    if (ds_oilInOut.getModifiedIndex().length < 1) {
        await $c.gus.cfAlertMsg("변경된 사항이 없습니다.");
        return;
    }

    var vaildArray = [
        { id: "reqInDt", name: "요청일자", mandatory: true, valid: "date", format: "YYYYMMDD", legnth: 8 },
        { id: "clntNo", name: "거래처코드", mandatory: true },
        { id: "oilkndCd", name: "유종", mandatory: true },
        { id: "reqQty", name: "리터(L)", mandatory: true, minNumber: 1 },
        { id: "reqSelfTransYn", name: "자가운송여부", mandatory: true },
        { id: "reqInHm", name: "입고요청시간", mandatory: true, legnth: 4 },
        { id: "reqNm", name: "요청자", mandatory: true },
        { id: "mpNo", name: "휴대전화", mandatory: true }
    ];

    var chk = await $c.gus.cfValidateGrid(gr_oilInOut, null, null, vaildArray, "유류구매요청내역");

    if (!chk) return;

    for (var i = 0; i < ds_oilInOut.getRowCount(); i++) {
        if (ds_oilInOut.getRowJSON(i).reqSelfTransYn == "1" && ds_oilInOut.getRowJSON(i).transVehclNo == "") {
            await $c.win.alert((i + 1) + "번째행 자가운송일때 차량번호는 필수입력입니다.");
            return;
        }
    }

    if (await $c.win.confirm(MSG_CM_CRM_001)) { 				//저장하시겠습니까?
        $c.sbm.execute(sbm_saveOilOrder);
    }
};

scwin.sbm_saveOilOrder_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        await $c.gus.cfAlertMsg(MSG_CM_INF_001);
        scwin.f_Retrieve()

    };
};

//-------------------------------------------------------------------------
// 입고요청
//-------------------------------------------------------------------------
scwin.f_Fix = async function (e) {
    if (gr_oilInOut.getCheckedIndex("chk").length == 0) {
        await $c.win.alert('선택된 데이타가 존재하지 않습니다.');
        return;
    }

    var vaildArray = [
        { id: "reqInDt", name: "요청일자", mandatory: true, valid: "date", format: "YYYYMMDD" },
        { id: "clntNo", name: "거래처코드", mandatory: true },
        { id: "oilkndCd", name: "유종", mandatory: true },
        { id: "reqQty", name: "리터(L)", mandatory: true, minNumber: 1 },
        { id: "reqSelfTransYn", name: "자가운송여부", mandatory: true },
        { id: "reqInHm", name: "입고요청시간", mandatory: true, length: 4 },
        { id: "reqNm", name: "요청자", mandatory: true },
        { id: "mpNo", name: "휴대전화", mandatory: true },
    ]

    if (!await $c.gus.cfValidateGrid(gr_oilInOut, null, null, vaildArray, "유류구매요청내역")) {
        return;
    }

    var chkRowIdx = gr_oilInOut.getCheckedIndex("chk");
    for (var i = 0; i < chkRowIdx.length; i++) {
        if (ds_oilInOut.getCellData(chkRowIdx[i], "stsCd") != "0") {
            await $c.win.alert(chkRowIdx[i] + "번째행은 대기상태가 아닙니다.");
            return;
        }
    }

    for (var i = 0; i < ds_oilInOut.getRowCount(); i++) {
        if (ds_oilInOut.getCellData(i, "reqSelfTransYn") == "1" && ds_oilInOut.getCellData(i, "transVehclNo") == "") {
            await $c.win.alert((i + 1) + "번째행 자가운송일때 차량번호는 필수입력입니다.");
            return;
        }
    }

    var cnt = 0;
    if (await $c.win.confirm("입고요청을 하시겠습니까?")) {
        for (var i = 0; i < chkRowIdx.length; i++) {
            if (ds_oilInOut.getCellData(chkRowIdx[i], "stsCd") == "0") {
                ds_oilInOut.setCellData(chkRowIdx[i], "inYn", "F");
                cnt = cnt + 1;
            }
        }

        if (cnt > 0) {
            $c.sbm.execute(sbm_fix);
        }
    }
};

scwin.sbm_fix_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        await $c.gus.cfAlertMsg("입고요청 되었습니다.");
        scwin.f_Retrieve();
    }
};

//-------------------------------------------------------------------------
// 입고요청 취소
//-------------------------------------------------------------------------
scwin.f_Cancle = async function (e) {
    if (gr_oilInOut.getCheckedIndex("chk").length == 0) {
        await $c.win.alert('선택된 데이타가 존재하지 않습니다.');
        return;
    }

    if (!await $c.gus.cfValidate(gr_oilInOut)) {
        return;
    }

    var chkRowIdx = gr_oilInOut.getCheckedIndex("chk");

    for (var i = 0; i < chkRowIdx.length; i++) {
        if (ds_oilInOut.getCellData(chkRowIdx[i], "stsCd") != "1") {
            await $c.win.alert((chkRowIdx[i] + 1) + "번째행은 요청상태가 아닙니다.");
            return;
        }
    }

    var cnt = 0;
    if (await $c.win.confirm("입고요청을 취소하시겠습니까?")) {
        for (var i = 0; i < chkRowIdx.length; i++) {
            if (ds_oilInOut.getCellData(chkRowIdx[i], "stsCd") == "1") {
                ds_oilInOut.setCellData(chkRowIdx[i], "inYn", "C");
                cnt = cnt + 1;
            }
        }

        if (cnt > 0) {
            $c.sbm.execute(sbm_cancle);
        }
    }
};

scwin.sbm_cancle_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != 'FAIL') {
        await $c.gus.cfAlertMsg("입고요청이 취소되었습니다.");
        scwin.f_Retrieve()
    };
};

//-------------------------------------------------------------------------
// 체크항목 ==> tobe 삭제: gr_oilInOut.getCheckedIndex("chk").length로 체크
//-------------------------------------------------------------------------
