//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------
scwin.f_AddRow = async function () {
    var focusCol = gr_oilInOut.getFocusedColumnIndex();

    ds_oilInOut.insertRow();

    //tobe추가 : 그리드 포커스 셋팅
    gr_oilInOut.setFocusedCell(ds_oilInOut.getRowCount() - 1, 0);
    ds_oilInOut.setRowPosition(ds_oilInOut.getRowCount() - 1);

    ds_oilInOut.setCellData(ds_oilInOut.getRowPosition(), 'reqRegDt', $c.date.getServerDateTime("yyyyMMdd"));
    ds_oilInOut.setCellData(ds_oilInOut.getRowPosition(), 'reqInDt', $c.date.getServerDateTime("yyyyMMdd"));
    ds_oilInOut.setCellData(ds_oilInOut.getRowPosition(), 'stsCd', "0");
    ds_oilInOut.setCellData(ds_oilInOut.getRowPosition(), 'reqSelfTransYn', "0");
    ds_oilInOut.setCellData(ds_oilInOut.getRowPosition(), 'clntNo', ed_clntNo.getValue());
    ds_oilInOut.setCellData(ds_oilInOut.getRowPosition(), 'clntNm', ed_clntNm.getValue());
    ds_oilInOut.setCellData(ds_oilInOut.getRowPosition(), 'reqOilStatNo', ed_reqOilStatNo.getValue());
    ds_oilInOut.setCellData(ds_oilInOut.getRowPosition(), 'reqOilStatNm', ed_reqOilStatNm.getValue());

    if (ed_reqOilStatNo.getValue() != "") {
        var clntNo = ds_oilInOut.getCellData(ds_oilInOut.getRowPosition(), "clntNo");
        clntNo = "";

        await udc_grReqOilStatNo.cfCommonPopUp(scwin.udc_grReqOilStatNo_callbackFunc, ed_reqOilStatNo.getValue(), "", 'T', null, null, null, null, clntNo, null, null, null, null); // 거래처
    }

    if (!$c.gus.cfIsNull(scwin.clntNo)) {
        ds_oilInOut.setCellData(ds_oilInOut.getRowPosition(), 'clntNo', scwin.clntNo);
        ds_oilInOut.setCellData(ds_oilInOut.getRowPosition(), 'clntNm', scwin.clntNm);
        gr_oilInOut.setColumnReadOnly('clntNo', true);
        gr_oilInOut.setColumnReadOnly('clntNm', true);
    }
};

scwin.udc_grReqOilStatNo_callbackFunc = function (rtnList) {
    if (rtnList != null && rtnList[0] != "N/A") {
        ds_oilInOut.setCellData(ds_oilInOut.getRowPosition(), "reqOilStatNo", rtnList[0]);
        ds_oilInOut.setCellData(ds_oilInOut.getRowPosition(), "reqOilStatNm", rtnList[1]);
        ds_oilInOut.setCellData(ds_oilInOut.getRowPosition(), "mpNo", rtnList[2]);
        ds_oilInOut.setCellData(ds_oilInOut.getRowPosition(), "reqNm", rtnList[3]);
    }
};

//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.f_DelRow = async function () {
    var focusRow = gr_oilInOut.getFocusedRowIndex(); //현재 포커스 되어있는 row
    var focusCol = gr_oilInOut.getFocusedColumnIndex(); //현재 포커스 되어있는 column

    if (ds_oilInOut.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);  // 조회결과가 존재하지 않습니다.
        return;
    }

    var stsCd = ds_oilInOut.getCellData(focusRow, "stsCd");

    if (stsCd == "1" || stsCd == "2" || stsCd == "3") { 	// 0:대기,1:요청, 2:발주, 3:입고
        await $c.gus.cfAlertMsg((focusRow + 1) + "번째 항목은 삭제 할 수 없습니다.\n발주상태를 확인해 주시기바랍니다.");
        return;
    }

    //tobe 변경 : 추가된 행 삭제시 화면에서도 바로 삭제. 추가된 행이 아닌경우, 화면에서는 지워지지 않고 status만 삭제표시
    //ds_oilInOut.deleteRow(row);
    if (ds_oilInOut.getRowStatus(focusRow) == "C") { //추가된 행
        ds_oilInOut.removeRow(focusRow)

    } else {
        ds_oilInOut.deleteRow(focusRow);

        for (var i = 0; i < 24; i++) {
            ds_oilInOut.setCellData(focusRow, ds_oilInOut.getColumnID(i), ds_oilInOut.getOriginalCellData(focusRow, ds_oilInOut.getColumnID(i)));
        }

        //deleteRow 이후, 포커스 유지
        gr_oilInOut.setFocusedCell(focusRow, focusCol);
        gr_oilInOut.setRowReadOnly(focusRow, true);
        gr_oilInOut.setCellReadOnly(focusRow, "chk", true);
    }
};

//-------------------------------------------------------------------------
// 	팝업창 처리
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
    switch (disGubun) {
        case 1:
            // 거래처
            await udc_clntNo.cfCommonPopUp(scwin.udc_clntNo_callbackFunc	// XML상의 SELECT ID	
                , pCode					// 화면에서의 ??? Code Element의	Value
                , pName					// 화면에서의 ??? Name Element의	Value
                , 'T'					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                , null					// Title순서	
                , null					// 보여주는 각 컬럼들의 폭	
                , null					// 컬럼중에서 숨기는	컬럼 지정	
                , null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                , null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                , null					// 윈도우 위치 Y좌표	
                , null					// 윈도우 위치 X좌표
                , null					// 중복체크여부	("F")
                , null					// 전체검색허용여부	("F")
                , null				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            );
            break;
        case 2:
            // 주유소
            var clntNo = ed_clntNo.getValue()
            clntNo = "";

            await udc_reqOilStatNo.cfCommonPopUp(scwin.udc_reqOilStatNo_callbackFunc, pCode, "", 'T', null, null, null, null, clntNo, null, null, null, null);
            break;
        default:
            break;
    }
};

scwin.udc_clntNo_callbackFunc = function (rtnList) {
    if (!$c.gus.cfIsNull(rtnList) && rtnList[0] != "N/A") {
        $c.gus.cfSetReturnValue(rtnList, ed_clntNo, ed_clntNm);
    } else {
        ed_clntNo.setValue("");
        ed_clntNm.setValue("");
    }
};

scwin.udc_reqOilStatNo_callbackFunc = function (rtnList) {
    if (!$c.gus.cfIsNull(rtnList) && rtnList[0] != "N/A") {
        $c.gus.cfSetReturnValue(rtnList, ed_reqOilStatNo, ed_reqOilStatNm);
    } else {
        ed_reqOilStatNo.setValue("");
        ed_reqOilStatNm.setValue("");
    }
};

//-------------------------------------------------------------------------
// 	그리드 팝업창 처리
//-------------------------------------------------------------------------
scwin.f_openPopUp = async function (row, colid, data) {
    var pCode = "";
    scwin.curRow = row;

    if (colid == 'clntNo') {
        pCode = data; //ds_oilInOut.getCellData(row, "clntNo");
        await udc_grClnt.cfCommonPopUp(scwin.udc_grClnt_callbackFunc, pCode, "", 'T', null, null, null, null, null, null, null, null, null); // 거래처
    }

    if (colid == 'reqOilStatNm') {
        var clntNo = ds_oilInOut.getCellData(row, "clntNo");
        clntNo = "";

        await udc_grReqOilStatNo.cfCommonPopUp(scwin.udc_grReqOilStatNo_callbackFunc, pCode, "", 'T', null, null, null, null, clntNo, null, null, null, null); // 주유소
    }
};

scwin.udc_grClnt_callbackFunc = function (rtnList) {
    if (!$c.gus.cfIsNull(rtnList) && rtnList[0] != "N/A") {
        ds_oilInOut.setCellData(scwin.curRow, "clntNo", rtnList[0]);
        ds_oilInOut.setCellData(scwin.curRow, "clntNm", rtnList[1]);
    } else {
        ds_oilInOut.setCellData(scwin.curRow, "clntNo", "");
        ds_oilInOut.setCellData(scwin.curRow, "clntNm", "");
    }

    scwin.curRow = -1;
};

scwin.udc_grReqOilStatNo_callbackFunc = function (rtnList) {
    if (!$c.gus.cfIsNull(rtnList) && rtnList[0] != "N/A") {
        ds_oilInOut.setCellData(scwin.curRow, "reqOilStatNo", rtnList[0]);
        ds_oilInOut.setCellData(scwin.curRow, "reqOilStatNm", rtnList[1]);
        ds_oilInOut.setCellData(scwin.curRow, "mpNo", rtnList[2]);
        ds_oilInOut.setCellData(scwin.curRow, "reqNm", rtnList[3]);
    } else {
        ds_oilInOut.setCellData(scwin.curRow, "reqOilStatNo", "");
        ds_oilInOut.setCellData(scwin.curRow, "reqOilStatNm", "");
        ds_oilInOut.setCellData(scwin.curRow, "mpNo", "");
        ds_oilInOut.setCellData(scwin.curRow, "reqNm", "");
    }

    scwin.curRow = -1;
};

scwin.gr_oilInOut_onafteredit = function (rowIndex, columnIndex, value) { 
    var colid = gr_oilInOut.getColumnID(columnIndex);
    var data = gr_oilInOut.getCellDisplayData(rowIndex, colid);

    if (colid == "clntNo") {
        ds_oilInOut.setCellData(rowIndex, "clntNo", "");
        ds_oilInOut.setCellData(rowIndex, "clntNm", "");
        scwin.f_openPopUp(rowIndex, colid, data);

    }else if(colid == "reqOilStatNm"){
        scwin.f_openPopUp(rowIndex, colid, data);
    }
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!await $c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if ($c.gus.cfIsNull(isCode) || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
        // inObj가 코드명 필드일 경우 팝업
    } else {
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
};

scwin.gr_oilInOut_oncellclick = async function (rowIndex, columnIndex, columnId) {
    // if( columnId == "clntNo" || columnId == "reqOilStatNo") {
    // 	gr_oilInOut.UrlImages = SEARCH_BTN;
    // }
    // if( columnId == "reqInDt") {
    //     gr_oilInOut.UrlImages = CALENDAR_BTN;
    // }

    if (columnId == "chk") {
        if (ds_oilInOut.getCellData(rowIndex, "stsCd") == "2" || ds_oilInOut.getCellData(rowIndex, "stsCd") == "3") {
            ds_oilInOut.setCellData(rowIndex, "chk", "F");
            await $c.win.alert("상태가 입고,발주인 것은 선택할수 없습니다.");
        } else {
            gr_oilInOut.setCellReadOnly(rowIndex, "chk", false);
        }
    }

    if (ds_oilInOut.getCellData(rowIndex, "stsCd") == "1" || ds_oilInOut.getCellData(rowIndex, "stsCd") == "2" || ds_oilInOut.getCellData(rowIndex, "stsCd") == "3") {
        gr_oilInOut.setColumnReadOnly("reqInDt", true);
        gr_oilInOut.setColumnReadOnly("clntNo", true);
        gr_oilInOut.setColumnReadOnly("oilkndCd", true);
        gr_oilInOut.setColumnReadOnly("reqQty", true);
        gr_oilInOut.setColumnReadOnly("reqNm", true);
        gr_oilInOut.setColumnReadOnly("mpNo", true);
        gr_oilInOut.setColumnReadOnly("stockQty", true);
        gr_oilInOut.setColumnReadOnly("etc", true);
        gr_oilInOut.setColumnReadOnly("reqOilStatNm", true);
        gr_oilInOut.setColumnReadOnly("reqSelfTransYn", true);
        gr_oilInOut.setColumnReadOnly("transVehclNo", true);
        gr_oilInOut.setColumnReadOnly("reqInHm", true);
        gr_oilInOut.setColumnReadOnly("reqInPlace", true);

    } else if (ds_oilInOut.getCellData(rowIndex, "stsCd") == "0") {
        gr_oilInOut.setColumnReadOnly("reqInDt", false);
        gr_oilInOut.setColumnReadOnly("clntNo", false);
        gr_oilInOut.setColumnReadOnly("oilkndCd", false);
        gr_oilInOut.setColumnReadOnly("reqQty", false);
        gr_oilInOut.setColumnReadOnly("reqNm", false);
        gr_oilInOut.setColumnReadOnly("mpNo", false);
        gr_oilInOut.setColumnReadOnly("stockQty", false);
        gr_oilInOut.setColumnReadOnly("etc", false);
        gr_oilInOut.setColumnReadOnly("reqOilStatNm", false);
        gr_oilInOut.setColumnReadOnly("reqSelfTransYn", false);
        gr_oilInOut.setColumnReadOnly("transVehclNo", false);
        gr_oilInOut.setColumnReadOnly("reqInHm", false);
        gr_oilInOut.setColumnReadOnly("reqInPlace", false);

        if (!$c.gus.cfIsNull(scwin.clntNo)) {
            gr_oilInOut.setColumnReadOnly("clntNo", true);
        }
    }
};

