//-------------------------------------------------------------------------
// 취소
//-------------------------------------------------------------------------
scwin.f_CancelRow = function () {
    var focusRow = gr_oilInOut.getFocusedRowIndex();
    var focusCol = gr_oilInOut.getFocusedColumnID();

    if (ds_oilInOut.getRowStatus(ds_oilInOut.getRowPosition()) == "C") {
        ds_oilInOut.removeRow(ds_oilInOut.getRowPosition());
    } else {
        ds_oilInOut.undoRow(ds_oilInOut.getRowPosition());
        gr_oilInOut.setCellReadOnly(ds_oilInOut.getRowPosition(), "chk", false); //체크박스 
        gr_oilInOut.setRowReadOnly(focusRow, true);
    }
};

